183	// Check if Claude CLI works (detects context management incompatibility)
184	let claudeCompatible = null; // null = not yet checked, boolean = cached
185	
186	function checkClaudeCompatibility() {
187	  if (claudeCompatible !== null) return claudeCompatible;
188	  const env = buildEnvScript();
189	  try {
190	    execSync(`"${env.CLAUDE_BIN}" --version`, { stdio: 'pipe' });
191	    // Try a quick API call to see if context management works
192	    execSync(
193	      `CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS='${env.CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS}' ` +
194	      `ANTHROPIC_BASE_URL='${env.ANTHROPIC_BASE_URL}' ` +
195	      `ANTHROPIC_AUTH_TOKEN='${env.ANTHROPIC_AUTH_TOKEN}' ` +
196	      `ANTHROPIC_API_KEY='${env.ANTHROPIC_API_KEY}' ` +
197	      `ANTHROPIC_MODEL='${env.ANTHROPIC_MODEL}' ` +
198	      `CLAUDECODE='' "${env.CLAUDE_BIN}" --print -p "hi" 2>&1`,
199	      { stdio: 'pipe', timeout: 15000 }
200	    );
201	    claudeCompatible = true;
202	    return true;
203	  } catch (e) {
204	    claudeCompatible = false;
205	    return false;
206	  }
207	}
