449	// API: Shutdown and clean up a team
450	app.delete('/api/teams/:name', (req, res) => {
451	  try {
452	    const teamName = req.params.name;
453	    const teamPath = path.join(TEAMS_DIR, teamName);
454	    const taskPath = path.join(CLAUDE_DIR, 'tasks', teamName);
455	    const pidFile = path.join(PID_DIR, `${teamName}.pid`);
