463	      fs.unlinkSync(pidFile);
464	    }
465	
466	    if (fs.existsSync(teamPath)) {
467	      try {
468	        fs.rmSync(teamPath, { recursive: true, force: true });
469	      } catch (e) {
470	        const configFile = path.join(teamPath, 'config.json');
471	        if (fs.existsSync(configFile)) fs.unlinkSync(configFile);
472	      }
473	    }
474	    if (fs.existsSync(taskPath)) {
475	      fs.rmSync(taskPath, { recursive: true, force: true });
476	    }
477	
478	    res.json({ success: true, message: `Team "${teamName}" removed` });
479	  } catch (err) {
