552	    // Build commands with trust-bypass flags
553	    const commands = agents.map(agent => {
554	      const isTrevor = agent.name.toLowerCase() === 'trevor';
555	      let cmd = `cd "${projectDir}" && CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 ${claudePath} -r ${agent.teamName}`;
556	      if (isTrevor) cmd += ' --agent=trevor';
557	      cmd += ' --permission-mode acceptEdits';
558	      return cmd;
559	    });
560	
561	    // Mark all agents as being launched
562	    for (const agent of agents) {
563	      const teamConfigPath = path.join(TEAMS_DIR, agent.teamName, 'config.json');
564	      try {
565	        const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
