567	        member.backgroundId = `${agent.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}-launched-${Date.now()}`;
568	        fs.writeFileSync(teamConfigPath, JSON.stringify(config, null, 2));
569	      } catch {}
570	    }
571	
572	    // Return commands to frontend — frontend will run osascript from GUI context
573	    res.json({
574	      success: true,
575	      message: `Launching ${agents.length} agent(s)...`,
576	      count: agents.length,
577	      commands: agents.map((a, i) => ({ name: a.name, command: commands[i] }))
578	    });
579	  } catch (err) {
580	    res.status(500).json({ success: false, error: err.message });
581	  }
582	});
