645	  ctx.fillStyle = '#1a1a2e';
646	  const eyeOffX = player.dir === 'left' ? -2 : player.dir === 'right' ? 2 : 0;
647	  const eyeOffY = player.dir === 'up' ? -4 : player.dir === 'down' ? 2 : 0;
648	  if (player.dir !== 'up') {
649	    ctx.fillRect(screenX + 19 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
650	    ctx.fillRect(screenX + 26 + eyeOffX, screenY + 8 + bob + eyeOffY, 3, 3);
