// Open a new Terminal.app tab and run a command via osascript
function openTerminalTab(title, command) {
  // Escape for AppleScript: double quotes become \", backslashes become \\
  const escapedTitle = title.replace(/\\/g, '\\\\').replace(/"/g, '" & quote & "');
  const escapedCmd = command.replace(/\\/g, '\\\\').replace(/"/g, '" & quote & "');
  const script = `
    tell application "Terminal"
      if not (exists window 1) then do script ""
      activate
      do script "echo '=== Agent: ${escapedTitle} ===' && ${escapedCmd}" in front window
      set custom title of front window to "${escapedTitle}"
      set title displays custom title of front window to true
    end tell
  `;
  try {
    execSync(`osascript -e '${script}'`, { stdio: 'pipe', timeout: 10000 });
    return true;
  } catch (e) {
    console.error(`Failed to open Terminal for ${title}:`, e.message);
    return false;
  }
}

