1	const express = require('express');
2	const fs = require('fs');
3	const path = require('path');
4	const { exec, execSync, spawn } = require('child_process');
5	
6	const app = express();
7	app.use(express.json());
8	app.use(express.static(path.join(__dirname, 'public')));
9	
10	const CLAUDE_DIR = path.join(process.env.HOME, '.claude');
11	const TEAMS_DIR = path.join(CLAUDE_DIR, 'teams');
12	const DESCRIPTIONS_FILE = path.join(__dirname, 'agents.json');
13	const PID_DIR = path.join(__dirname, '.pids');
14	
15	// Known built-in agent types that have their own definitions
16	const KNOWN_AGENT_TYPES = ['trevor', 'luca', 'ellie', 'general-purpose', 'Explore', 'Plan', 'code-reviewer', 'silent-failure-hunter', 'manager'];
17	
18	if (!fs.existsSync(PID_DIR)) fs.mkdirSync(PID_DIR, { recursive: true });
19	
20	// Load custom agent descriptions
21	function loadDescriptions() {
22	  try {
23	    return JSON.parse(fs.readFileSync(DESCRIPTIONS_FILE, 'utf8'));
24	  } catch {
25	    return {};
26	  }
27	}
28	
29	function saveDescriptions(descs) {
30	  fs.writeFileSync(DESCRIPTIONS_FILE, JSON.stringify(descs, null, 2));
31	}
32	
33	// Lookup the canonical key in a case-insensitive way
34	function lookupDescriptionKey(descriptions, target) {
35	  if (descriptions[target]) return target;
36	  const lower = target.toLowerCase();
37	  for (const key of Object.keys(descriptions)) {
38	    if (key.toLowerCase() === lower) return key;
39	  }
40	  return null;
41	}
42	
43	function checkPidAlive(pid) {
44	  try {
45	    process.kill(pid, 0);
46	    return true;
47	  } catch {
48	    return false;
49	  }
50	}
51	
52	function savePid(filename, pid) {
53	  fs.writeFileSync(path.join(PID_DIR, filename), String(pid));
54	}
55	
56	function loadPid(filename) {
57	  try {
58	    return parseInt(fs.readFileSync(path.join(PID_DIR, filename), 'utf8'), 10);
59	  } catch {
60	    return 0;
61	  }
62	}
63	
64	// Get all running agents from teams config files
65	function getRunningAgents() {
66	  const agents = [];
67	  const descriptions = loadDescriptions();
68	
69	  if (!fs.existsSync(TEAMS_DIR)) return agents;
70	
71	  const teamDirs = fs.readdirSync(TEAMS_DIR);
72	
73	  for (const teamName of teamDirs) {
74	    const teamConfigPath = path.join(TEAMS_DIR, teamName, 'config.json');
75	    try {
76	      const config = JSON.parse(fs.readFileSync(teamConfigPath, 'utf8'));
77	
78	      if (config.members && config.members.length > 0) {
79	        for (const member of config.members) {
80	          const agentId = member.agentId;
81	
82	          // Lookup description case-insensitively
83	          let description = '';
84	          const descKey = lookupDescriptionKey(descriptions, member.name);
85	          if (descKey) {
86	            description = descriptions[descKey];
87	          } else if (KNOWN_AGENT_TYPES.includes(member.agentType)) {
88	            const typeDescKey = lookupDescriptionKey(descriptions, member.agentType);
89	            if (typeDescKey) description = descriptions[typeDescKey];
