484	// Open a new Terminal.app tab and run a command via osascript
485	function openTerminalTab(title, command) {
486	  // Escape for AppleScript: double quotes become \", backslashes become \\
487	  const escapedTitle = title.replace(/\\/g, '\\\\').replace(/"/g, '" & quote & "');
488	  const escapedCmd = command.replace(/\\/g, '\\\\').replace(/"/g, '" & quote & "');
489	  const script = `
490	    tell application "Terminal"
491	      if not (exists window 1) then do script ""
492	      activate
493	      do script "echo '=== Agent: ${escapedTitle} ===' && ${escapedCmd}" in front window
494	      set custom title of front window to "${escapedTitle}"
495	      set title displays custom title of front window to true
496	    end tell
497	  `;
498	  try {
499	    execSync(`osascript -e '${script}'`, { stdio: 'pipe', timeout: 10000 });
500	    return true;
501	  } catch (e) {
502	    console.error(`Failed to open Terminal for ${title}:`, e.message);
503	    return false;
504	  }
505	}
