  if (!fs.existsSync(tmpDir)) fs.mkdirSync(tmpDir, { recursive: true });
  const scriptFile = path.join(tmpDir, `launch-${Date.now()}.scpt`);

  // Write AppleScript to a temp file to avoid shell quoting issues
  const appleScript = `
tell application "Terminal"
  if not (exists window 1) then do script ""
  activate
  do script "echo '=== Agent: ${title} ===' && ${command}" in front window
  set custom title of front window to "${title}"
  set title displays custom title of front window to true
end tell
`;
  fs.writeFileSync(scriptFile, appleScript, 'utf8');

  try {
    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 10000 });
    // Clean up after a short delay
    setTimeout(() => { try { fs.unlinkSync(scriptFile); } catch {} }, 3000);
    return true;
  } catch (e) {
    console.error(`Failed to open Terminal for ${title}:`, e.message);
    try { fs.unlinkSync(scriptFile); } catch {}
    return false;
  }
}

