    for (const agent of result.commands) {
      script += `\necho "Launching ${agent.name}..."\n${agent.command} &\nsleep 1\n`;
    }
    script += `\necho "All agents launched!"\n`;

    const blob = new Blob([script], { type: 'application/octet-stream' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'launch-all-agents.command';
    a.click();
    URL.revokeObjectURL(url);

    showNotification(`<strong>Downloading launch script for ${result.count} agent(s)...</strong><br>Double-click the downloaded file to open all terminals.`, 10000);
    setTimeout(refreshData, 3000);
  } catch (err) {
    console.error('Wake agents up error:', err);
    showNotification('Failed to launch agents.', 3000);
  }
};

