// Open a new Terminal.app window and run the agent command.
// Writes command to a persistent .sh file per agent, avoids all quoting issues.
function openTerminalTab(title, command) {
  const agentDir = path.join(__dirname, '.agents');
  if (!fs.existsSync(agentDir)) fs.mkdirSync(agentDir, { recursive: true });

  const safeName = title.toLowerCase().replace(/[^a-z0-9]/g, '-');
  const shellFile = path.join(agentDir, `${safeName}.sh`);
  fs.writeFileSync(shellFile, `#!/bin/bash\nset -e\necho "=== Agent: ${title} ==="\n${command}\n`, 'utf8');
  fs.chmodSync(shellFile, '755');

  // Open a new Terminal window WITHOUT bringing it to front
  // We use a single monolithic AppleScript to avoid race conditions
  const appleScript = `tell application "Terminal"
    do script "${shellFile}"
    delay 1
    repeat with w in windows
      if custom title of w is "" or custom title of w is missing value then
        set custom title of w to "${title}"
        set title displays custom title of w to true
        set miniaturized of w to true
        exit repeat
      end if
    end repeat
end tell
`;
  const scriptFile = path.join(agentDir, `${safeName}.scpt`);
  fs.writeFileSync(scriptFile, appleScript, 'utf8');

  try {
    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 15000 });
    return true;
  } catch (e) {
    console.error(`Failed to open Terminal for ${title}: ${e.message}`);
    return false;
  }
}

