});

// API: Save/update agent description
app.put('/api/agents/:id/description', (req, res) => {
  try {
    const descriptions = loadDescriptions();
    const id = req.params.id;
    descriptions[id] = req.body.description || '';
    saveDescriptions(descriptions);
