    const isTrevor = agent.name.toLowerCase() === 'trevor';
    let cmd = `claude -r ${agent.teamName}`;
    if (isTrevor) cmd += ' --agent=trevor';
    cmd += ' --permission-mode acceptEdits';
    script += `echo "Launching ${agent.name}..." && ${cmd} &\nsleep 0.5\n`;
