    const safeName = agent.title.toLowerCase().replace(/[^a-z0-9]/g, '-');
    const shellFile = path.join(AGENT_DIR, `${safeName}.sh`);
    const escapedPath = shellFile.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    const escapedTitle = agent.title.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    appleScript += `  do script "${escapedPath}"\n`;
    appleScript += `  delay 0.4\n`;
    // Set title and miniaturize immediately after each window opens
    appleScript += `  set w to (windows whose custom title is missing value)\n`;
    appleScript += `  if (count of w) > 0 then\n`;
    appleScript += `    set newWin to item 1 of w\n`;
    appleScript += `    set custom title of newWin to "${escapedTitle}"\n`;
    appleScript += `    set title displays custom title of newWin to true\n`;
    appleScript += `    set miniaturized of newWin to true\n`;
    appleScript += `  end if\n`;
  }
  appleScript += `end tell\n`;

  const scriptFile = path.join(AGENT_DIR, `launch-all-${Date.now()}.scpt`);
  fs.writeFileSync(scriptFile, appleScript, 'utf8');

  try {
    execSync(`osascript "${scriptFile}"`, { stdio: 'pipe', timeout: 60000 });
    setTimeout(() => { try { fs.unlinkSync(scriptFile); } catch {} }, 10000);
    return true;
  } catch (e) {
    console.error(`Failed to launch all agents in Terminal: ${e.message}`);
    try { fs.unlinkSync(scriptFile); } catch {}
    return false;
  }
}

